diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..63619d313149 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -9425,7 +9425,40 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
       (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_UGE) &&
       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
     return CmpPredicate::getMatching(LPred, RPred).has_value();
-
+  // Handle ptrdiff != 0 implying pointer inequality.
+  // LHS: icmp eq/ne (sub (ptrtoint A), (ptrtoint B)), C
+  // RHS: icmp eq/ne A, B
+  // Also handles truncation of ptrtoint.
+  auto getPointerOperand = [&](Value *V) -> Value * {
+    Value *Ptr;
+    if (match(V, m_PtrToInt(m_Value(Ptr))))
+      return Ptr;
+    if (match(V, m_Trunc(m_PtrToInt(m_Value(Ptr)))))
+      return Ptr;
+    return nullptr;
+  };
+  Value *X, *Y;
+  if (match(L0, m_Sub(m_Value(X), m_Value(Y)))) {
+    Value *A = getPointerOperand(X);
+    Value *B = getPointerOperand(Y);
+    if (A && B && ((A == R0 && B == R1) || (A == R1 && B == R0))) {
+      // If LHS is equality and RHS is inequality, and C is known non-zero,
+      // then sub == C != 0 implies A != B.
+      if (LPred == ICmpInst::ICMP_EQ && RPred == ICmpInst::ICMP_NE &&
+          computeKnownBits(L1, DL).isNonZero())
+        return true;
+      // If LHS is inequality and RHS is inequality, and C is known zero,
+      // then sub != 0 implies A != B.
+      if (LPred == ICmpInst::ICMP_NE && RPred == ICmpInst::ICMP_NE &&
+          computeKnownBits(L1, DL).isZero())
+        return true;
+      // If LHS is equality and RHS is equality, and C is known zero,
+      // then sub == 0 implies A == B.
+      if (LPred == ICmpInst::ICMP_EQ && RPred == ICmpInst::ICMP_EQ &&
+          computeKnownBits(L1, DL).isZero())
+        return true;
+  }
+}
   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);

